# 프로필 수정 API 인터페이스 설계

## 1. 현재 프로젝트 구조 분석 결과

SKILL.md에서 확인한 프로젝트 패턴:

| 항목 | 확인된 패턴 |
|------|-------------|
| 모듈 구조 | `graphql/`, `protobuf/`, `domain/` 분리 |
| DB Catalog | `maum` (user, profile 도메인) |
| GraphQL Input 명명 | `{Action}{Domain}Input` (예: `CreateFeatureInput`) |
| Mutation 명명 | camelCase 동사 + 명사 |
| 인증 | `@PreAuthorize("hasAuthority('User')")` + `@UserId userId: String` |
| gRPC 메서드 | `Update` prefix 사용 |
| Proto 필드 | `snake_case` |

---

## 2. GraphQL 스키마 설계

파일 위치: `/graphql/src/main/resources/graphql/profile.graphqls`

```graphql
# =====================
# Enum Types
# =====================

enum Gender {
    MALE
    FEMALE
    OTHER
}

# =====================
# 프로필 수정 Input Types
# =====================

input UpdateProfileInput {
    # 기본 정보 (모두 선택적 - 변경하려는 필드만 전달)
    nickname: String
    introduction: String
    profileImageUrl: String
    birthDate: String            # "YYYY-MM-DD" 형식
    gender: Gender
    heightCm: Int
    job: String
    region: String               # 활동 지역 (ex: "서울 강남구")

    # 소셜/데이팅 앱 특화 필드
    interests: [String!]         # 관심사 태그 목록 (ex: ["음악", "여행", "독서"])
    personalities: [String!]     # 성격 태그 목록 (ex: ["활발한", "차분한"])
    idealTypeDescription: String # 이상형 한줄 소개

    # 음성 통화 앱 특화 필드
    voiceIntroUrl: String        # 음성 자기소개 URL
    languages: [String!]         # 사용 가능 언어 (ex: ["ko", "en"])
}

input UpdateProfileImageInput {
    profileImageUrl: String!
    thumbnailImageUrl: String
}

# =====================
# Response Types
# =====================

type ProfileResponse {
    userId: ID!
    nickname: String!
    introduction: String
    profileImageUrl: String
    thumbnailImageUrl: String
    birthDate: String
    age: Int                     # 서버 계산 값 (read-only)
    gender: Gender
    heightCm: Int
    job: String
    region: String
    interests: [String!]!
    personalities: [String!]!
    idealTypeDescription: String
    voiceIntroUrl: String
    languages: [String!]!
    updatedAt: String!
}

# =====================
# Mutation 확장
# =====================

extend type Mutation {
    # 프로필 전체 수정 (변경된 필드만 선택적으로 전달)
    updateProfile(input: UpdateProfileInput!): ProfileResponse!

    # 프로필 이미지만 별도 수정 (이미지 업로드 후 URL 전달)
    updateProfileImage(input: UpdateProfileImageInput!): ProfileResponse!

    # 관심사 태그 일괄 교체
    updateProfileInterests(interests: [String!]!): ProfileResponse!
}

extend type Query {
    # 내 프로필 조회
    myProfile: ProfileResponse!

    # 타인 프로필 조회
    userProfile(userId: ID!): ProfileResponse
}
```

