## 3. gRPC Proto 설계

파일 위치: `/protobuf/src/main/proto/profile/profile_service.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

// =====================
// Service 정의
// =====================

service ProfileService {
  rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
  rpc UpdateProfileImage(UpdateProfileImageRequest) returns (UpdateProfileResponse);
  rpc UpdateProfileInterests(UpdateProfileInterestsRequest) returns (UpdateProfileResponse);
}

// =====================
// Message: Profile 공통 타입
// =====================

message Profile {
  string user_id = 1;
  string nickname = 2;
  string introduction = 3;
  string profile_image_url = 4;
  string thumbnail_image_url = 5;
  string birth_date = 6;           // "YYYY-MM-DD"
  int32 age = 7;                   // 서버 계산
  string gender = 8;               // "MALE" | "FEMALE" | "OTHER"
  int32 height_cm = 9;
  string job = 10;
  string region = 11;
  repeated string interests = 12;
  repeated string personalities = 13;
  string ideal_type_description = 14;
  string voice_intro_url = 15;
  repeated string languages = 16;
  string updated_at = 17;
}

// =====================
// GetProfile
// =====================

message GetProfileRequest {
  string requester_user_id = 1;    // 요청자 (권한 확인용)
  string target_user_id = 2;       // 조회 대상
}

message GetProfileResponse {
  Profile profile = 1;
}

// =====================
// UpdateProfile
// =====================

message UpdateProfileRequest {
  string user_id = 1;

  // optional 필드: 값이 있는 경우만 업데이트 적용
  optional string nickname = 2;
  optional string introduction = 3;
  optional string birth_date = 4;
  optional string gender = 5;
  optional int32 height_cm = 6;
  optional string job = 7;
  optional string region = 8;
  optional string ideal_type_description = 9;
  optional string voice_intro_url = 10;
  repeated string interests = 11;       // 빈 리스트 = 변경 없음, hasInterests 플래그 활용
  repeated string personalities = 12;
  repeated string languages = 13;
  optional bool has_interests = 14;     // interests 업데이트 여부 플래그
  optional bool has_personalities = 15;
  optional bool has_languages = 16;
}

message UpdateProfileResponse {
  Profile profile = 1;
}

// =====================
// UpdateProfileImage
// =====================

message UpdateProfileImageRequest {
  string user_id = 1;
  string profile_image_url = 2;
  optional string thumbnail_image_url = 3;
}

// =====================
// UpdateProfileInterests
// =====================

message UpdateProfileInterestsRequest {
  string user_id = 1;
  repeated string interests = 2;
}
```

