## 5. GraphQL Service (gRPC Client) 구현 예시

파일 위치: `/graphql/src/main/kotlin/com/maum/backend/service/profile/ProfileService.kt`

```kotlin
@Service
class ProfileService {
    @GrpcClient("profile-grpc")
    private lateinit var stub: ProfileServiceGrpc.ProfileServiceBlockingStub

    fun getProfile(requesterUserId: String, targetUserId: String): GetProfileResponse {
        val request = GetProfileRequest.newBuilder()
            .setRequesterUserId(requesterUserId)
            .setTargetUserId(targetUserId)
            .build()
        return try {
            stub.getProfile(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateProfile(userId: String, input: UpdateProfileInput): UpdateProfileResponse {
        val builder = UpdateProfileRequest.newBuilder().setUserId(userId)

        input.nickname?.let { builder.setNickname(it) }
        input.introduction?.let { builder.setIntroduction(it) }
        input.birthDate?.let { builder.setBirthDate(it) }
        input.gender?.let { builder.setGender(it.name) }
        input.heightCm?.let { builder.setHeightCm(it) }
        input.job?.let { builder.setJob(it) }
        input.region?.let { builder.setRegion(it) }
        input.idealTypeDescription?.let { builder.setIdealTypeDescription(it) }
        input.voiceIntroUrl?.let { builder.setVoiceIntroUrl(it) }

        input.interests?.let {
            builder.addAllInterests(it)
            builder.setHasInterests(true)
        }
        input.personalities?.let {
            builder.addAllPersonalities(it)
            builder.setHasPersonalities(true)
        }
        input.languages?.let {
            builder.addAllLanguages(it)
            builder.setHasLanguages(true)
        }

        return try {
            stub.updateProfile(builder.build())
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateProfileImage(userId: String, input: UpdateProfileImageInput): UpdateProfileResponse {
        val builder = UpdateProfileImageRequest.newBuilder()
            .setUserId(userId)
            .setProfileImageUrl(input.profileImageUrl)

        input.thumbnailImageUrl?.let { builder.setThumbnailImageUrl(it) }

        return try {
            stub.updateProfileImage(builder.build())
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateProfileInterests(userId: String, interests: List<String>): UpdateProfileResponse {
        val request = UpdateProfileInterestsRequest.newBuilder()
            .setUserId(userId)
            .addAllInterests(interests)
            .build()
        return try {
            stub.updateProfileInterests(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

